import{_ as i,o as a,c as r,a2 as t}from"./chunks/framework.DZrHScmQ.js";const p=JSON.parse('{"title":"ARTI-D007: Shared Identifier Drift Review","description":"","frontmatter":{"status":"Proposed","owner":"待指定","scope":"project","project":"arti","decision_id":"ARTI-D007","date":"2026-06-15T00:00:00.000Z","last_reviewed":"2026-06-15T00:00:00.000Z"},"headers":[],"relativePath":"projects/arti/decisions/ARTI-D007-shared-identifier-drift-review.md","filePath":"projects/arti/decisions/ARTI-D007-shared-identifier-drift-review.md"}'),o={name:"projects/arti/decisions/ARTI-D007-shared-identifier-drift-review.md"};function d(l,e,n,s,c,h){return a(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="arti-d007-shared-identifier-drift-review" tabindex="-1">ARTI-D007: Shared Identifier Drift Review <a class="header-anchor" href="#arti-d007-shared-identifier-drift-review" aria-label="Permalink to &quot;ARTI-D007: Shared Identifier Drift Review&quot;">​</a></h1><p><strong>状态：Proposed</strong></p><p><strong>Owner：待指定</strong></p><p><strong>日期：2026-06-15</strong></p><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>ARTI 多仓共享 <code>AnswerKind</code>、<code>NotificationKind</code>、Report Type、Stock Symbol 和 DTO 字段名。部分值已有多份实现或历史 alias，<code>shared-identifiers.md</code> 已标记为 <code>Current with Known Drift</code>。</p><h2 id="决策" tabindex="-1">决策 <a class="header-anchor" href="#决策" aria-label="Permalink to &quot;决策&quot;">​</a></h2><p>共享标识符漂移必须按 <a href="./../playbooks/known-drift-review.html">Known Drift Review</a> 复核。</p><p>约束：</p><ul><li>共享字符串是协议，不是展示文案。</li><li>单仓不得独自引入新的 canonical 值。</li><li>alias、fallback 和双读路径必须有退出条件。</li><li>影响 Credits、结算、权限或数据完整性的漂移需要升级。</li><li>Review 输出应回写到相关 Contract、Decision 和仓库文档。</li></ul><h2 id="替代方案" tabindex="-1">替代方案 <a class="header-anchor" href="#替代方案" aria-label="Permalink to &quot;替代方案&quot;">​</a></h2><ul><li>各仓自行映射：快，但会扩大隐式协议面。</li><li>立即共享包化：方向正确，但当前迁移成本较高。</li><li>只写提醒：不能阻止后续继续漂移。</li></ul><p>因此先用 Drift Review 收敛行为，再决定是否共享包化。</p><h2 id="影响" tabindex="-1">影响 <a class="header-anchor" href="#影响" aria-label="Permalink to &quot;影响&quot;">​</a></h2><ul><li>正向：减少跨仓枚举、DTO 和 Symbol 漂移。</li><li>代价：跨仓改动前多一步复核。</li><li>影响仓库：<code>arti</code>、<code>ARTI_backend</code>、<code>ARTi-poly</code>、<code>ARTI-CLI</code>。</li></ul><h2 id="实施与验证" tabindex="-1">实施与验证 <a class="header-anchor" href="#实施与验证" aria-label="Permalink to &quot;实施与验证&quot;">​</a></h2><ol><li><code>shared-identifiers.md</code> 链接 Known Drift Review。</li><li>新增或修改共享标识前列出生产者、消费者、canonical 值和兼容期。</li><li>高风险标识补固定用例或跨仓检查。</li><li>删除 alias / fallback 前确认生产数据和消费者已迁移。</li></ol><p>验证：<code>npm run check</code> 通过，相关 PR 链接本决策或 Known Drift Review。</p><h2 id="取代关系" tabindex="-1">取代关系 <a class="header-anchor" href="#取代关系" aria-label="Permalink to &quot;取代关系&quot;">​</a></h2><ul><li>Supersedes：无</li><li>Superseded by：无</li></ul>',20)])])}const u=i(o,[["render",d]]);export{p as __pageData,u as default};
